using ModelContextProtocol.Server;
using System.ComponentModel;
using System.Text.Json;

namespace McpHttpServer;

[McpServerResourceType]
public static class ConfigResource
{
    private static readonly Dictionary<string, object> _config = new()
    {
        ["appName"] = "MyMcpService",
        ["version"] = "1.0.0",
        ["maxRetries"] = 3,
        ["timeoutSeconds"] = 30,
        ["features"] = new Dictionary<string, bool>
        {
            ["darkMode"] = true,
            ["notifications"] = true,
            ["betaFeatures"] = false
        }
    };

    [McpServerResource(UriTemplate = "config://app/settings",
        Name = "app-settings",
        Description = "Returns the current application configuration as JSON")]
    public static string GetAppSettings()
    {
        return JsonSerializer.Serialize(_config, new JsonSerializerOptions { WriteIndented = true });
    }

    [McpServerResource(UriTemplate = "config://app/settings/{section}",
        Name = "app-settings-section",
        Description = "Returns a specific configuration section")]
    public static string GetConfigSection(string section)
    {
        if (_config.TryGetValue(section, out var value))
        {
            return JsonSerializer.Serialize(value, new JsonSerializerOptions { WriteIndented = true });
        }

        return JsonSerializer.Serialize(new { error = $"Section '{section}' not found" });
    }
}

using ModelContextProtocol.Server;
using System.ComponentModel;

namespace McpHttpServer;

[McpServerToolType]
public static class EchoTool
{
    [McpServerTool(Name = "echo"), Description("Echoes back the provided message")]
    public static string Echo([Description("The message to echo")] string message)
    {
        return $"Echo: {message}";
    }

    [McpServerTool(Name = "get_timestamp"), Description("Returns the current UTC timestamp")]
    public static string GetTimestamp()
    {
        return DateTime.UtcNow.ToString("o");
    }
}

